import { useEffect, useState } from "react";
import { Table, Card, Button, Tag, Space, Input } from "antd";
import { DeleteOutlined, SearchOutlined } from "@ant-design/icons";

function History() {
  const [tickets, setTickets] = useState([]);
  const [searchText, setSearchText] = useState("");

  // Load tickets from localStorage
  useEffect(() => {
    const storedTickets =
      JSON.parse(localStorage.getItem("tickets")) || [];
    setTickets(storedTickets);
  }, []);

  // Clear all tickets
  const clearAllTickets = () => {
    localStorage.removeItem("tickets");
    setTickets([]);
  };

  // Priority badge colors
  const getPriorityColor = (priority) => {
    switch (priority) {
      case "Low":
        return "green";
      case "Medium":
        return "orange";
      case "High":
        return "red";
      case "Critical":
        return "red";
      default:
        return "default";
    }
  };

  // Status badge colors
  const getStatusColor = (status) => {
    switch (status) {
      case "Resolved":
      case "Auto-Resolved":
        return "success";
      case "Open":
        return "processing";
      default:
        return "default";
    }
  };

  // Table columns configuration
  const columns = [
    {
      title: "Ticket ID",
      dataIndex: "Ticket_ID",
      key: "Ticket_ID",
      fixed: "left",
      width: 150,
      render: (text) => <span className="font-mono font-semibold">{text}</span>,
      filteredValue: searchText ? [searchText] : null,
      onFilter: (value, record) =>
        record.Ticket_ID.toLowerCase().includes(value.toLowerCase()) ||
        record.Category.toLowerCase().includes(value.toLowerCase()) ||
        (record.Summary || "").toLowerCase().includes(value.toLowerCase()),
    },
    {
      title: "Category",
      dataIndex: "Category",
      key: "Category",
      width: 150,
      filters: [...new Set(tickets.map((t) => t.Category))].map((cat) => ({
        text: cat,
        value: cat,
      })),
      onFilter: (value, record) => record.Category === value,
      render: (text) => <Tag color="blue">{text}</Tag>,
    },
    {
      title: "Sub-Category",
      dataIndex: "Sub_Category",
      key: "Sub_Category",
      width: 150,
      render: (text) => text && text !== "N/A" ? <Tag color="cyan">{text}</Tag> : <span className="text-gray-400">-</span>,
    },
    {
      title: "Priority",
      dataIndex: "Priority",
      key: "Priority",
      width: 120,
      filters: [
        { text: "Low", value: "Low" },
        { text: "Medium", value: "Medium" },
        { text: "High", value: "High" },
        { text: "Critical", value: "Critical" },
      ],
      onFilter: (value, record) => record.Priority === value,
      sorter: (a, b) => {
        const priorityOrder = { Low: 1, Medium: 2, High: 3, Critical: 4 };
        return priorityOrder[a.Priority] - priorityOrder[b.Priority];
      },
      render: (text) => (
        <Tag color={getPriorityColor(text)} className="font-medium">
          {text}
        </Tag>
      ),
    },
    {
      title: "Status",
      dataIndex: "Resolution_Status",
      key: "Resolution_Status",
      width: 140,
      filters: [
        { text: "Open", value: "Open" },
        { text: "Resolved", value: "Resolved" },
        { text: "Auto-Resolved", value: "Auto-Resolved" },
      ],
      onFilter: (value, record) => record.Resolution_Status === value,
      render: (text) => <Tag color={getStatusColor(text)}>{text}</Tag>,
    },
    {
      title: "Assigned Team",
      dataIndex: "Assigned_Team",
      key: "Assigned_Team",
      width: 150,
      filters: [...new Set(tickets.map((t) => t.Assigned_Team).filter(Boolean))].map((team) => ({
        text: team,
        value: team,
      })),
      onFilter: (value, record) => record.Assigned_Team === value,
      render: (text) => text || <span className="text-gray-400">-</span>,
    },
    {
      title: "Channel",
      dataIndex: "Channel",
      key: "Channel",
      width: 120,
    },
    {
      title: "Routing Confidence",
      dataIndex: "Routing_Confidence",
      key: "Routing_Confidence",
      width: 160,
      sorter: (a, b) => (a.Routing_Confidence || 0) - (b.Routing_Confidence || 0),
      render: (value) => {
        if (!value) return <span className="text-gray-400">-</span>;
        const percentage = Math.round(value * 100);
        const color = percentage > 80 ? "green" : percentage > 50 ? "orange" : "red";
        return <Tag color={color}>{percentage}%</Tag>;
      },
    },
    {
      title: "Timestamp",
      dataIndex: "Timestamp",
      key: "Timestamp",
      width: 180,
      sorter: (a, b) => new Date(a.Timestamp || 0) - new Date(b.Timestamp || 0),
      defaultSortOrder: "descend",
      render: (text) => {
        if (!text) return <span className="text-gray-400">-</span>;
        return new Date(text).toLocaleString();
      },
    },
  ];

  return (
    <div className="p-4 md:p-8">
      <Card
        title={
          <div className="flex justify-between items-center">
            <h2 className="text-2xl font-bold m-0">Ticket History</h2>
            <Space>
              <Input
                placeholder="Search tickets..."
                prefix={<SearchOutlined />}
                value={searchText}
                onChange={(e) => setSearchText(e.target.value)}
                style={{ width: 250 }}
                allowClear
              />
              {tickets.length > 0 && (
                <Button
                  danger
                  icon={<DeleteOutlined />}
                  onClick={clearAllTickets}
                >
                  Clear All
                </Button>
              )}
            </Space>
          </div>
        }
        bordered={false}
      >
        <Table
          columns={columns}
          dataSource={tickets}
          rowKey="Ticket_ID"
          pagination={{
            pageSize: 10,
            showSizeChanger: true,
            showTotal: (total) => `Total ${total} tickets`,
          }}
          scroll={{ x: 1400 }}
          locale={{
            emptyText: "No tickets submitted yet. Submit your first ticket to see it here.",
          }}
        />
      </Card>
    </div>
  );
}

export default History;

import { useState, useEffect, useRef } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { BrainCircuit, Upload, X, ImageIcon, ArrowRight, AlertCircle, Sparkles, ChevronRight, Bell, Mic, CheckCircle2 } from "lucide-react";
// eslint-disable-next-line no-unused-vars
import { motion, AnimatePresence } from "framer-motion";
import useTicketStore from "../store/ticketStore";
import { api } from "../services/api";

function Submit() {
  const [issue, setIssue] = useState("");
  const [title, setTitle] = useState("");
  const [category, setCategory] = useState("api-integration");
  const [file, setFile] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef(null);

  const navigate = useNavigate();
  const setAITicket = useTicketStore((state) => state.setAITicket);
  const setActiveTicket = useTicketStore((state) => state.setActiveTicket);
  const currentUser = JSON.parse(sessionStorage.getItem("currentUser") || "{}");

  const location = useLocation();
  const locationState = location.state || {};

  useEffect(() => {
    setActiveTicket(null);
    if (!currentUser || !currentUser.username) {
      navigate("/login");
    }

    // Set prefilled category if passed from Dashboard QuickActions
    if (locationState.prefilledCategory) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setCategory(locationState.prefilledCategory.toLowerCase());
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentUser, navigate, location.state]);

  useEffect(() => {
    return () => {
      if (imagePreview) URL.revokeObjectURL(imagePreview);
    };
  }, [imagePreview]);

  const handleFileChange = (e) => {
    const selected = e.target.files?.[0];
    if (!selected) return;

    if (imagePreview) URL.revokeObjectURL(imagePreview);
    setFile(selected);
    setImagePreview(URL.createObjectURL(selected));
  };

  const handleRemoveImage = () => {
    if (imagePreview) URL.revokeObjectURL(imagePreview);
    setFile(null);
    setImagePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!issue.trim() || !title.trim()) {
      setError("Please provide a title and describe your issue before submitting.");
      return;
    }

    setError("");
    setLoading(true);

    try {
      let imageBase64 = "";
      if (file) {
        imageBase64 = await new Promise((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => {
            const base64String = reader.result.split(',')[1];
            resolve(base64String);
          };
          reader.readAsDataURL(file);
        });
      }

      const fullIssue = `Title: ${title}\nCategory: ${category}\n\nDescription:\n${issue}`;
      const response = await api.predictTicket(fullIssue, imageBase64);
      const ticketData = response.data;

      setAITicket({
        ...ticketData,
        originalIssue: fullIssue,
        capturedFile: file
      });

      navigate("/ai-understanding");
    } catch (_err) {
      setError("AI Analysis failed. Please try again.");
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex-1 flex flex-col items-center justify-start py-12 px-4 sm:px-6">

        {/* Main Content */}
        <main className="flex-1 flex flex-col items-center justify-start py-12 px-4 sm:px-6">
          <motion.div
            initial={{ opacity: 0, scale: 0.98 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ duration: 0.4 }}
            className="w-full max-w-[680px] flex flex-col gap-6"
          >
            {/* Breadcrumbs */}
            <div className="flex items-center gap-2 text-sm text-[var(--stitch-text-muted,#618975)]">
              <span>Support</span>
              <ChevronRight className="w-4 h-4" />
              <span className="text-[var(--stitch-text-main,#111814)] font-medium">New Ticket</span>
            </div>

            {/* Card */}
            <div className="bg-[var(--stitch-surface-light,#ffffff)] dark:bg-[var(--stitch-surface-dark,#1a2e24)] rounded-[var(--stitch-radius,0.5rem)] shadow-lg border border-[var(--stitch-border-light,#e2e8e5)] dark:border-[var(--stitch-border-dark,#2a4034)] overflow-hidden">
              {/* Hero Image Area */}
              <div className="relative h-48 w-full bg-slate-100 overflow-hidden">
                <div className="absolute inset-0 bg-gradient-to-r from-[var(--stitch-primary,#13ec80)]/20 to-blue-500/20 mix-blend-multiply"></div>
                <div className="w-full h-full bg-gradient-to-br from-[var(--stitch-background-light,#f6f8f7)] to-slate-200 opacity-80"></div>
                <div className="absolute bottom-0 left-0 w-full p-6 bg-gradient-to-t from-black/60 to-transparent">
                  <h1 className="text-white text-2xl font-bold tracking-tight">Describe your issue</h1>
                  <p className="text-white/90 text-sm mt-1">Our AI agent focuses on this issue instantly.</p>
                </div>
