    const [error, setError] = useState("");
    const [timeLeft, setTimeLeft] = useState(900);
    const [timerExpired, setTimerExpired] = useState(false);

    // Only re-run when step changes. DO NOT add timeLeft to deps array.
    useEffect(() => {
        if (step !== 2) return;
        setTimerExpired(false);
        setTimeLeft(900);
        const timer = setInterval(() => {
            setTimeLeft((prev) => {
                if (prev <= 1) {
                    clearInterval(timer);
                    setTimerExpired(true);
                    return 0;
                }
                return prev - 1;
            });
        }, 1000);
        return () => clearInterval(timer);
    }, [step]); // eslint-disable-line react-hooks/exhaustive-deps

    const formatTime = (seconds) => {
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins}:${secs.toString().padStart(2, '0')}`;
    };

    const handleSendOtp = async (e) => {
        e.preventDefault();
        if (!email) {
            setError("Please enter your email address");
            return;
        }

        setLoading(true);
        setError("");

        try {
            // With Email OTP enabled in Supabase, resetPasswordForEmail sends
            // a 6-digit numeric OTP instead of a magic link.
            const { error } = await supabase.auth.resetPasswordForEmail(email);

            if (error) throw error;

            setMessage("Check your email for the 6-digit recovery code!");
            setStep(2);
        } catch (err) {
            console.error("Password reset error:", err);
            setError(err.message || "An error occurred. Please try again.");
        } finally {
            setLoading(false);
        }
    };

    const handleVerifyOtp = async (e) => {
        e.preventDefault();
        if (!otp || otp.length !== 6) {
            setError("Please enter the 6-digit code");
            return;
        }
        if (timerExpired) {
            setError("Your code has expired. Please request a new one.");
            return;
        }

        setLoading(true);
        setError("");

        try {
            const { error } = await supabase.auth.verifyOtp({
                email,
                token: otp,
                type: 'recovery'
            });

            if (error) throw error;
            setStep(3);
            setMessage("Code verified. Please enter your new password.");
        } catch (err) {
            console.error("OTP verification error:", err);
            setError("Invalid or expired code. Please check your email and try again.");
        } finally {
            setLoading(false);
        }
    };

    const handleUpdatePassword = async (e) => {
        e.preventDefault();
        if (!newPassword || newPassword.length < 6) {
            setError("Password must be at least 6 characters long.");
            return;
        }

        setLoading(true);
        setError("");

        try {
            const { error } = await supabase.auth.updateUser({
                password: newPassword
            });

            if (error) throw error;
            setStep(4);
        } catch (err) {
            console.error("Update password error:", err);
            setError(err.message || "Failed to update password.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center font-sans relative overflow-hidden p-6 py-12" style={{ background: 'linear-gradient(160deg, #f0fdf4 0%, #dcfce7 60%, #bbf7d0 100%)' }}>
            {/* Background Patterns */}
            <div className="absolute top-0 left-0 w-full h-full opacity-[0.03] pointer-events-none" style={{ backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")` }}></div>
            <div className="absolute top-0 left-0 w-[500px] h-[500px] bg-emerald-500/10 rounded-full blur-[120px] -translate-x-1/2 -translate-y-1/2 pointer-events-none"></div>

            <div className="w-full max-w-md relative z-10">
                {/* Logo Header */}
                <div className="flex justify-center mb-10">
                    <Link to="/" className="flex items-center gap-2 bg-white/40 backdrop-blur-xl px-5 py-2.5 rounded-2xl border border-white/40 shadow-xl shadow-emerald-900/5 transition hover:bg-white/60 group">
                        <BrainCircuit className="w-6 h-6 text-emerald-600 transition-transform group-hover:rotate-12" />
                        <span className="font-extrabold text-xl tracking-tight text-[#0f1f12]" style={{ fontFamily: 'Syne' }}>HelpDesk<span className="text-emerald-600">.ai</span></span>
                    </Link>
                </div>

                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="bg-white shadow-[0_20px_50px_rgba(0,0,0,0.08)] rounded-[2.5rem] p-10 border border-white/50 relative overflow-hidden"
                >
                    {/* Header Decoration */}
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-emerald-400 to-emerald-600 opacity-20"></div>

                    <div className="text-center mb-10">
                        <h2 className="text-3xl font-black text-[#0f1f12] tracking-tight" style={{ fontFamily: 'Syne' }}>
                            {step === 1 ? "Recovery Access" : step === 2 ? "Verify Identity" : "Secure Protocol"}
                        </h2>
                        <p className="text-gray-500 mt-2 font-medium">
                            {step === 1 ? "Enter your email to initiate recovery." : step === 2 ? "Enter the 6-digit code sent to your email." : "Set a new high-security password."}
                        </p>
                    </div>

                    <AnimatePresence mode="wait">
                        {step === 4 ? (
                            <motion.div 
                                key="success"
                                initial={{ opacity: 0, scale: 0.95 }}
                                animate={{ opacity: 1, scale: 1 }}
                                className="text-center py-6"
                            >
                                <div className="w-20 h-20 rounded-3xl bg-emerald-50 border border-emerald-100 flex items-center justify-center mx-auto mb-8 shadow-inner">
                                    <CheckCircle2 className="w-10 h-10 text-emerald-600" />
                                </div>
                                <h3 className="text-xl font-bold text-gray-900 mb-3">Sync Successful</h3>
                                <p className="text-gray-500 font-medium mb-10 leading-relaxed">
                                    Your security credentials have been updated across all nodes.
                                </p>
                                <Link
                                    to="/login"
                                    className="inline-flex items-center justify-center w-full px-8 py-4 bg-[#0f1f12] text-white rounded-2xl font-bold hover:bg-emerald-900 transition-all shadow-xl shadow-emerald-900/20 active:scale-[0.98]"
                                >
                                    Proceed to Terminal
                                </Link>
                            </motion.div>
                        ) : (
                            <div className="space-y-6">
                                {error && (
                                    <motion.div 
                                        initial={{ opacity: 0, height: 0 }}
                                        animate={{ opacity: 1, height: 'auto' }}
                                        className="bg-red-50 border border-red-100 text-red-600 px-5 py-4 rounded-2xl text-sm font-semibold flex items-start gap-3"
                                    >
                                        <AlertCircle className="w-5 h-5 shrink-0" />
                                        <p>{error}</p>
                                    </motion.div>
                                )}

                                {message && step !== 1 && (
                                    <div className="bg-emerald-50 border border-emerald-100 text-emerald-700 px-5 py-4 rounded-2xl text-sm font-semibold flex items-start gap-3">
                                        <CheckCircle2 className="w-5 h-5 shrink-0" />
                                        <p>{message}</p>
                                    </div>
                                )}

                                {/* STEP 1: Email */}
                                {step === 1 && (
                                    <form onSubmit={handleSendOtp} className="space-y-6">
                                        <div className="space-y-2">
                                            <label className="text-xs font-black uppercase tracking-widest text-gray-400 ml-1">Identity Terminal</label>
                                            <div className="relative">
                                                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
                                                    <Mail className="w-5 h-5" />
                                                </div>
                                                <input
                                                    type="email"
                                                    placeholder="personnel@helpdesk.ai"
                                                    className="w-full pl-12 pr-4 py-4 rounded-2xl border border-gray-100 focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/5 transition-all outline-none text-gray-900 font-bold bg-gray-50/50"
                                                    value={email}
                                                    onChange={(e) => setEmail(e.target.value)}
                                                    required
                                                />
                                            </div>
                                        </div>

                                        <button
                                            type="submit"
                                            disabled={loading}
                                            className="w-full rounded-2xl py-4 font-bold transition-all flex items-center justify-center gap-2 group"
                                            style={{ background: 'linear-gradient(135deg, #16a34a, #22c55e)', color: '#fff', boxShadow: '0 10px 30px rgba(34,160,69,0.2)' }}
                                            onMouseEnter={(e) => e.currentTarget.style.transform = 'translateY(-2px)'}
                                            onMouseLeave={(e) => e.currentTarget.style.transform = 'translateY(0)'}
                                        >
                                            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <>Request Access Key <ArrowLeft className="w-5 h-5 rotate-180 transition-transform group-hover:translate-x-1" /></>}
                                        </button>
                                    </form>
                                )}

                                {/* STEP 2: OTP */}
                                {step === 2 && (
                                    <form onSubmit={handleVerifyOtp} className="space-y-8">
                                        <div className="space-y-4">
                                            <label className="text-xs font-black uppercase tracking-widest text-gray-400 text-center block">Verification Sequence</label>
                                            <div className="relative flex justify-center">
                                                <input
                                                    type="text"
                                                    maxLength="6"
                                                    placeholder="000000"
                                                    className="w-full text-center tracking-[0.5em] text-4xl px-4 py-6 rounded-3xl border border-gray-100 focus:border-emerald-500 focus:ring-8 focus:ring-emerald-500/5 transition-all outline-none text-emerald-600 font-black bg-gray-50/50 shadow-inner"
                                                    style={{ fontFamily: 'monospace' }}
                                                    value={otp}
                                                    onChange={(e) => setOtp(e.target.value.replace(/[^0-9]/g, ''))}
                                                    autoFocus
                                                />
                                            </div>
                                            <p className={`text-center text-xs font-bold mt-1 ${
                                                timerExpired ? 'text-red-500' : timeLeft < 60 ? 'text-orange-500' : 'text-gray-400'
                                            }`}>
                                                {timerExpired ? '⚠ Code expired — request a new one below' : `Expires in ${formatTime(timeLeft)}`}
                                            </p>
                                        </div>

                                        <button
                                            type="submit"
                                            disabled={loading || otp.length < 6 || timerExpired}
                                            className="w-full rounded-2xl py-4 font-bold transition-all flex items-center justify-center gap-2"
                                            style={{ background: timerExpired ? '#e5e7eb' : 'linear-gradient(135deg, #16a34a, #22c55e)', color: timerExpired ? '#9ca3af' : '#fff', boxShadow: timerExpired ? 'none' : '0 10px 30px rgba(34,160,69,0.2)' }}
                                            onMouseEnter={(e) => { if (!timerExpired) e.currentTarget.style.transform = 'translateY(-2px)'; }}
                                            onMouseLeave={(e) => e.currentTarget.style.transform = 'translateY(0)'}
                                        >
                                            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : "Verify Identity Signature"}
                                        </button>
                                        {timerExpired && (
                                            <button
                                                type="button"
                                                onClick={() => { setStep(1); setOtp(""); setError(""); }}
                                                className="w-full rounded-2xl py-3 font-bold text-sm transition-all flex items-center justify-center gap-2 border-2 border-emerald-500 text-emerald-600 hover:bg-emerald-50"
                                            >
                                                Request New Code
                                            </button>
                                        )}
                                    </form>
                                )}

                                {/* STEP 3: New Password */}
                                {step === 3 && (
                                    <form onSubmit={handleUpdatePassword} className="space-y-6">
                                        <div className="space-y-4">
                                            <div className="space-y-2">
                                                <label className="text-xs font-black uppercase tracking-widest text-gray-400 ml-1">New Security Sequence</label>
                                                <div className="relative">
                                                    <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
                                                        <Lock className="w-5 h-5" />
                                                    </div>
                                                    <input
                                                        type="password"
                                                        placeholder="••••••••"
                                                        className="w-full pl-12 pr-4 py-4 rounded-2xl border border-gray-100 focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/5 transition-all outline-none text-gray-900 font-bold bg-gray-50/50"
                                                        value={newPassword}
                                                        onChange={(e) => setNewPassword(e.target.value)}
                                                        required
                                                    />
                                                </div>
                                            </div>
                                        </div>

                                        <button
                                            type="submit"
                                            disabled={loading || newPassword.length < 6}
                                            className="w-full rounded-2xl py-4 font-bold transition-all flex items-center justify-center gap-2"
                                            style={{ background: 'linear-gradient(135deg, #16a34a, #22c55e)', color: '#fff', boxShadow: '0 10px 30px rgba(34,160,69,0.2)' }}
                                            onMouseEnter={(e) => e.currentTarget.style.transform = 'translateY(-2px)'}
                                            onMouseLeave={(e) => e.currentTarget.style.transform = 'translateY(0)'}
                                        >
                                            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <>Sync Credentials <KeyRound className="w-5 h-5" /></>}
                                        </button>
                                    </form>
                                )}

                                <div className="text-center pt-6 border-t border-gray-50 mt-4">
                                    <Link
                                        to="/login"
                                        className="inline-flex items-center gap-2 text-gray-400 hover:text-emerald-600 text-xs font-black uppercase tracking-widest transition-all"
                                    >
                                        <ArrowLeft className="w-4 h-4" />
                                        Return to Secure Gate
                                    </Link>
                                </div>
                            </div>
                        )}
                    </AnimatePresence>
                </motion.div>
            </div>
        </div>
    );
}

export default ForgotPassword;

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
    CheckCircle2, ArrowRight, Search, Database, Zap,
    AlertTriangle, Lightbulb, TicketCheck
} from 'lucide-react';
import useTicketStore from '../store/ticketStore';

/* ─── Animated progress steps at the top ─────────────────────────────────── */
const steps = [
    { icon: Search, label: 'Your Issue', desc: 'Captured & analysed' },
    { icon: Database, label: 'Case History', desc: 'Scanning 10 000+ cases' },
    { icon: Zap, label: 'Match Found', desc: 'Similarity calculated' },
];

function KnowledgeCheck() {
    const { aiTicket } = useTicketStore();
    const navigate = useNavigate();
    const [activeStep, setActiveStep] = useState(0);

    /* Animate the step indicators on mount */
    useEffect(() => {
        const timers = [
            setTimeout(() => setActiveStep(1), 600),
            setTimeout(() => setActiveStep(2), 1300),
        ];
        return () => timers.forEach(clearTimeout);
    }, []);

    useEffect(() => {
        if (!aiTicket) { navigate('/create-ticket'); return; }

        // Update status for timeline sync
        if (aiTicket.status !== 'duplicate_check') {
            useTicketStore.getState().setAITicket({ ...aiTicket, status: 'duplicate_check' });
        }

        if (!aiTicket.duplicate_ticket && !aiTicket.auto_resolve) navigate('/ticket-tracking');
    }, [aiTicket, navigate]);

    if (!aiTicket) return null;

    /* ── Derive resolution steps from AI data ── */
    const resolutionSteps = (() => {
        // Try common field names the AI backend might return
        const raw =
            aiTicket.resolution_steps ||
            aiTicket.suggested_solution ||
            aiTicket.solution_steps ||
            aiTicket.steps ||
            null;

        if (Array.isArray(raw) && raw.length > 0) return raw;
        if (typeof raw === 'string' && raw.trim()) {
            // Split on newlines or numbered list patterns
            return raw.split(/\n+/).map(s => s.replace(/^\d+[\.\)]\s*/, '').trim()).filter(Boolean);
        }
        return null; // no steps available
    })();

    const similarityPct = aiTicket.similarity_score
        ? Math.round(aiTicket.similarity_score * 100)
        : aiTicket.confidence
            ? Math.round(aiTicket.confidence * 100)
            : null;

    return (
        <main className="flex-1 w-full max-w-[820px] mx-auto px-6 py-12 flex flex-col gap-10">

            {/* ── Premium Dark Hero Header ── */}
            <div className="relative rounded-3xl overflow-hidden bg-slate-900 px-8 py-10 shadow-2xl shadow-slate-900/30">
                {/* Glow blobs */}
                <div className="absolute -top-20 -left-20 w-72 h-72 bg-emerald-500/10 rounded-full blur-3xl pointer-events-none" />
                <div className="absolute -bottom-20 right-0 w-80 h-80 bg-indigo-500/10 rounded-full blur-3xl pointer-events-none" />
                {/* Dot-grid overlay */}
                <div className="absolute inset-0 opacity-[0.04]"
                    style={{ backgroundImage: 'radial-gradient(circle, #fff 1px, transparent 1px)', backgroundSize: '24px 24px' }} />
                {/* Scanning beam */}
                <div className="absolute top-0 left-0 h-full pointer-events-none overflow-hidden w-full">
                    <div className="absolute top-0 bottom-0 w-[3px] bg-gradient-to-b from-transparent via-emerald-400/70 to-transparent"
                        style={{ animation: 'knowledgeScan 3.5s ease-in-out infinite' }} />
                </div>
                <style>{`@keyframes knowledgeScan{0%{left:0%;opacity:0}10%{opacity:1}90%{opacity:1}100%{left:100%;opacity:0}}`}</style>

                <div className="relative z-10">
                    {/* Live badge */}
                    <div className="inline-flex items-center gap-2 px-3 py-1.5 bg-emerald-500/10 border border-emerald-500/25 rounded-full mb-5">
                        <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse" />
                        <span className="text-[10px] font-black text-emerald-400 uppercase tracking-[0.18em]">Analyzing History</span>
                    </div>

                    <h1 className="text-2xl md:text-3xl font-black text-white tracking-tight mb-1">
                        Scanning our <span className="text-emerald-400">case history</span>
                    </h1>
                    <p className="text-slate-400 text-sm font-medium mb-9">
                        We searched previous issues to see if this problem was already solved.
                    </p>

                    {/* Glowing animated steps */}
                    <div className="flex items-center">
                        {steps.map((step, i) => {
                            const Icon = step.icon;
                            const done = i <= activeStep;
                            const active = i === activeStep;
                            return (
                                <React.Fragment key={i}>
                                    <div className={`flex flex-col items-center text-center transition-all duration-700 ${done ? 'opacity-100' : 'opacity-20'}`}>
                                        <div className="relative mb-3">
                                            {active && (
                                                <>
                                                    <span className="absolute inset-0 rounded-2xl bg-emerald-500/40 animate-ping" />
                                                    <span className="absolute -inset-2 rounded-3xl bg-emerald-500/10 blur-lg" />
                                                </>
                                            )}
                                            <div className={`relative w-14 h-14 rounded-2xl flex items-center justify-center shadow-lg transition-all duration-500
                                                ${active ? 'bg-emerald-500 text-white scale-110 shadow-emerald-500/50'
                                                    : done ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30'
                                                        : 'bg-white/5 text-slate-500 border border-white/10'}`}>
                                                <Icon size={22} />
                                            </div>
                                        </div>
                                        <p className={`text-[11px] font-black uppercase tracking-widest leading-none mb-1 transition-colors duration-500
                                            ${active ? 'text-white' : done ? 'text-slate-300' : 'text-slate-600'}`}>
                                            {step.label}
                                        </p>
                                        <p className={`text-[10px] font-medium hidden sm:block transition-colors duration-500
                                            ${active ? 'text-emerald-400' : 'text-slate-500'}`}>
                                            {step.desc}
                                        </p>
                                    </div>
                                    {i < steps.length - 1 && (
                                        <div className="flex-1 mx-4 mt-[-28px] relative h-[2px]">
                                            <div className="absolute inset-0 bg-white/10 rounded-full" />
                                            <div className="absolute inset-y-0 left-0 bg-emerald-400 rounded-full transition-all duration-700 shadow-[0_0_6px_rgba(52,211,153,0.5)]"
                                                style={{ width: i < activeStep ? '100%' : '0%' }} />
                                        </div>
                                    )}
                                </React.Fragment>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* ── Match card ── */}
            <div className="bg-white rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/40 overflow-hidden">

                {/* Header */}
                <div className="px-8 py-6 bg-amber-50 border-b border-amber-100 flex items-start gap-4">
                    <div className="p-2.5 bg-amber-100 rounded-xl shrink-0">
                        <AlertTriangle className="w-5 h-5 text-amber-600" />
                    </div>
                    <div>
                        <h2 className="text-base font-black text-amber-900 tracking-tight">Similar Issue Found</h2>
                        <p className="text-sm text-amber-700/80 mt-0.5 font-medium">
                            We found a previously resolved ticket that is
                            {similarityPct ? <strong className="text-amber-900"> {similarityPct}% similar</strong> : ' highly similar'} to your issue.
                        </p>
                    </div>
                </div>

                <div className="p-8 space-y-8">

                    {/* Matched ticket info */}
                    <div className="bg-slate-50 rounded-2xl border border-slate-100 p-6 space-y-3">
                        <div className="flex items-start justify-between gap-4">
                            <div className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest">
                                <TicketCheck size={14} className="text-emerald-500" />
                                Matched Ticket
                            </div>
                            <span className="px-2.5 py-1 bg-emerald-100 text-emerald-700 text-[10px] font-black rounded-full uppercase tracking-widest">
                                Resolved
                            </span>
                        </div>
                        <p className="text-sm font-bold text-slate-700 leading-relaxed">
                            #{aiTicket.duplicate_ticket || '—'} — {aiTicket.summary}
                        </p>
                        {similarityPct && (
                            <div className="space-y-1.5">
                                <div className="flex justify-between items-center">
                                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Similarity</span>
                                    <span className="text-xs font-black text-emerald-600">{similarityPct}%</span>
                                </div>
                                <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden">
                                    <div
                                        className="h-full bg-emerald-500 rounded-full transition-all duration-1000"
                                        style={{ width: `${similarityPct}%` }}
                                    />
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Suggested Solution — only rendered if AI provides steps */}
                    {resolutionSteps && resolutionSteps.length > 0 && (
                        <div className="space-y-4">
                            <div className="flex items-center gap-2">
                                <Lightbulb size={16} className="text-amber-500" />
                                <h3 className="text-xs font-black text-slate-800 uppercase tracking-widest">Suggested Solution</h3>
                            </div>
                            <ol className="space-y-3">
                                {resolutionSteps.map((step, i) => (
                                    <li key={i} className="flex items-start gap-4 p-4 bg-slate-50 rounded-2xl border border-slate-100">
                                        <span className="w-6 h-6 rounded-lg bg-emerald-600 text-white text-[11px] font-black flex items-center justify-center shrink-0 mt-0.5">
                                            {i + 1}
                                        </span>
                                        <span className="text-sm font-medium text-slate-700 leading-relaxed">{step}</span>
                                    </li>
                                ))}
                            </ol>
                        </div>
                    )}

                    {/* Actions */}
                    <div className="flex flex-col sm:flex-row gap-3 pt-2">
                        <button
                            onClick={() => navigate('/auto-resolve')}
                            className="flex-1 bg-emerald-600 text-white px-6 py-3.5 rounded-2xl text-sm font-black uppercase tracking-widest hover:bg-emerald-700 active:scale-[0.98] transition-all shadow-lg shadow-emerald-500/20 flex items-center justify-center gap-2"
                        >
                            <CheckCircle2 size={16} />
                            Try This Solution
                        </button>
                        <button
                            onClick={() => navigate('/ticket-tracking')}
                            className="flex-1 bg-white border border-slate-200 text-slate-700 px-6 py-3.5 rounded-2xl text-sm font-black uppercase tracking-widest hover:bg-slate-50 active:scale-[0.98] transition-all flex items-center justify-center gap-2"
                        >
